import{_ as a,o as r,c as n,ak as t}from"./chunks/framework.CRYrbBns.js";const h=JSON.parse(`{"title":"Entrainement de l'IA et utilisation d'OVH cloud","description":"","frontmatter":{},"headers":[],"relativePath":"8 - Entrainement de IA + OVH cloud.md","filePath":"8 - Entrainement de IA + OVH cloud.md"}`),i={name:"8 - Entrainement de IA + OVH cloud.md"};function s(o,e,c,d,u,l){return r(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="entrainement-de-l-ia-et-utilisation-d-ovh-cloud" tabindex="-1">Entrainement de l&#39;IA et utilisation d&#39;OVH cloud <a class="header-anchor" href="#entrainement-de-l-ia-et-utilisation-d-ovh-cloud" aria-label="Permalink to “Entrainement de l&#39;IA et utilisation d&#39;OVH cloud”">​</a></h1><blockquote><p>L&#39;entraînement du modèle IA nécessite un PC ou un serveur suffisamment puissant, équipé d&#39;une <strong>carte GPU</strong>. Si vous n&#39;en disposez pas, vous pouvez utiliser un service cloud.</p></blockquote><p>Nous avons utilisé <strong>OVH Cloud</strong>, qui propose 200 € de crédit gratuit pour tester leurs produits : <a href="https://www.ovhcloud.com/fr/?at_medium=search&amp;at_platform=g&amp;at_campaign=AdWords&amp;at_creation=search_EC_fr_fr_FR_multi_multi_brand-global_defsv_traffic()&amp;at_variant=773285290541&amp;at_network=search&amp;at_term=ovh%20cloud&amp;gad_source=1&amp;gad_campaignid=22994457054&amp;gbraid=0AAAAADfi-ml4Dh3J__eOvyh3CgWJfyS0u&amp;gclid=Cj0KCQjwmunNBhDbARIsAOndKplpF37Wg92XxPDOQ1UgYFwhHuHBnhC5H3e2ymDEXFaYdD3KdE6VIEcaAuk6EALw_wcB" target="_blank" rel="noreferrer">OVH-cloud</a><a href="https://www.ovhcloud.com/fr/public-cloud/?at_medium=search&amp;at_platform=g&amp;at_campaign=AdWords&amp;at_creation=search_EC_fr_fr_FR_cloud_publiccloud_undefinite_defsv_traffic(Public%20Cloud%20-%20Generic)&amp;at_variant=676696754581&amp;at_network=search&amp;at_term=h%C3%A9bergeur%20cloud%20ovh&amp;gad_source=1&amp;gad_campaignid=1917699556&amp;gbraid=0AAAAADfi-mlcZBm2ajVeVhfLMnOCzbJkz&amp;gclid=Cj0KCQjwmunNBhDbARIsAOndKpnHpl4AwL2leaafZDF0lepillyl4QO-n4cJ6nUWtUx0IlEHeqUraMYaAsnXEALw_wcB" target="_blank" rel="noreferrer">Offre OVH</a></p><p>Utiliser les serveurs d&#39;OVH nous permet ainsi d&#39;accéder à des machines suffisamment puissantes. Pour y avoir accéder, il suffit de créer une instance, comprenant un serveur contenant l&#39;équipement (GPU) que l&#39;on souhaite.</p><h2 id="creation-d-une-instance-ovh" tabindex="-1">Création d&#39;une instance OVH <a class="header-anchor" href="#creation-d-une-instance-ovh" aria-label="Permalink to “Création d&#39;une instance OVH”">​</a></h2><p>Créer une instance (serveur virtuel) en sélectionnant une configuration incluant un GPU adapté.</p><hr><h2 id="connexion-a-l-instance" tabindex="-1">Connexion à l&#39;instance <a class="header-anchor" href="#connexion-a-l-instance" aria-label="Permalink to “Connexion à l&#39;instance”">​</a></h2><p>Une fois l&#39;instance créée, se connecter via SSH en renseignant une clé SSH dans l&#39;interface OVH.</p><p>OVH propose un tutoriel officiel pour cette démarche : <a href="https://www.youtube.com/watch?v=v5G10wK7ksU" target="_blank" rel="noreferrer">Tutoriel vidéo OVH – Connexion SSH</a></p><hr><h2 id="transfert-des-fichiers-d-enregistrement-au-serveur" tabindex="-1">Transfert des fichiers d&#39;enregistrement au serveur <a class="header-anchor" href="#transfert-des-fichiers-d-enregistrement-au-serveur" aria-label="Permalink to “Transfert des fichiers d&#39;enregistrement au serveur”">​</a></h2><p>Transférer les fichiers d&#39;enregistrement et de calibration (dossier <code>huggingface</code>) vers le serveur.</p><blockquote><p>Pour rappel les fichiers sont contenus dans &quot;C:\\Users{votre_utilisateur}.cache\\huggingface&quot; sur une machine Windows.</p></blockquote><p>Avec <strong>PuTTY</strong> installé, utiliser la commande <code>pscp</code> : <code>pscp -i C:\\Users\\{votre_utilisateur}\\{clé_ssh].ppk C:\\Users\\{votre_utilisateur}\\Downloads\\{fichier_enregistrement}.zip ubuntu@{IP_serveur}:/home/ubuntu</code></p><h4 id="syntaxe-generique" tabindex="-1">Syntaxe générique : <a class="header-anchor" href="#syntaxe-generique" aria-label="Permalink to “Syntaxe générique :”">​</a></h4><p><code>pscp -i chemin_vers_votre_cle_ssh.ppk chemin_vers_votre_fichier_enregistrement.zip ubuntu@{IP_serveur}:chemin_destination_serveur</code></p><hr><h2 id="connection-au-compte-huggingface" tabindex="-1">Connection au compte huggingface <a class="header-anchor" href="#connection-au-compte-huggingface" aria-label="Permalink to “Connection au compte huggingface”">​</a></h2><p><code>hf login</code> Saisir la clé API disponible dans <strong>Profil → Access Tokens</strong> sur <a href="https://huggingface.co" target="_blank" rel="noreferrer">huggingface.co</a>.</p><hr><h2 id="lancement-de-l-entrainement" tabindex="-1">Lancement de l&#39;entrainement <a class="header-anchor" href="#lancement-de-l-entrainement" aria-label="Permalink to “Lancement de l&#39;entrainement”">​</a></h2><p><code>lerobot-train</code><code>--dataset.repo_id={User}/{dataset}</code><code>--policy.type=act</code><code>--output_dir=outputs/train/act_{dataset}</code><code>--job_name=act_so101_test</code><code>--policy.device=cuda</code><code>--wandb.enable=false</code><code>--policy.repo_id={User}/{dataset}</code></p><hr><h2 id="probleme-de-configuration-gpu-nvidia-drivers-cuda" tabindex="-1">Problème de configuration GPU Nvidia (drivers CUDA) <a class="header-anchor" href="#probleme-de-configuration-gpu-nvidia-drivers-cuda" aria-label="Permalink to “Problème de configuration GPU Nvidia (drivers CUDA)”">​</a></h2><p>Après le lancement, une erreur peut indiquer que la machine ne dispose pas de cœurs CUDA, même si la carte GPU en est équipée. Cela est dû à une <strong>incompatibilité de version des drivers CUDA</strong>.</p><p><strong>Solution :</strong></p><ol><li>Désinstaller les drivers <code>cuda_toolkit</code> existants.</li><li>Réinstaller la version correspondant au GPU du serveur.</li></ol><p><a href="https://developer.nvidia.com/cuda/toolkit" target="_blank" rel="noreferrer">plus d&#39;infos sur cuda toolkit</a></p><hr><h2 id="recuperation-des-fichiers-entraines-depuis-le-serveur" tabindex="-1">Récupération des fichiers entraînés depuis le serveur <a class="header-anchor" href="#recuperation-des-fichiers-entraines-depuis-le-serveur" aria-label="Permalink to “Récupération des fichiers entraînés depuis le serveur”">​</a></h2><p><code>pscp -i C:\\Users\\{votre_utilisateur}\\Downloads\\{clé_ssh}.ppk ubuntu@{IP_serveur}:/home/ubuntu/huggingface C:\\Users\\{votre_utilisateur}\\Downloads</code></p><h4 id="syntaxe-generique-1" tabindex="-1">Syntaxe générique : <a class="header-anchor" href="#syntaxe-generique-1" aria-label="Permalink to “Syntaxe générique :”">​</a></h4><p><code>pscp -i chemin_vers_votre_cle_ssh.ppk ubuntu@{IP_serveur}:chemin_vers_votre_fichier_entrainés.zip Chemin_destination_PC</code></p>',34)])])}const m=a(i,[["render",s]]);export{h as __pageData,m as default};
